-- Добавляем статьи УПК РФ (права обвиняемого, задержание, арест)
INSERT INTO "t_p38294978_open_source_program_".egsu_legal_articles
(document_id, article_number, title, content, tags) VALUES

(3, 'Статья 46', 'Подозреваемый', 'Подозреваемым является лицо: 1) либо в отношении которого возбуждено уголовное дело; 2) которое задержано в соответствии со статьями 91 и 92 настоящего Кодекса; 3) к которому применена мера пресечения до предъявления обвинения. Подозреваемый вправе знать, в чём он подозревается; давать объяснения и показания по поводу имеющегося подозрения либо отказаться от дачи объяснений и показаний; пользоваться помощью защитника и иметь свидание с ним наедине до первого допроса; представлять доказательства; заявлять ходатайства и отводы.', ARRAY['подозреваемый', 'упк', 'права', 'задержание']),

(3, 'Статья 47', 'Обвиняемый', 'Обвиняемым признаётся лицо, в отношении которого вынесено постановление о привлечении его в качестве обвиняемого. Обвиняемый вправе: знать, в чём он обвиняется; получить копию постановления о привлечении его в качестве обвиняемого; возражать против обвинения, давать показания по предъявленному ему обвинению либо отказаться от дачи показаний; представлять доказательства; заявлять ходатайства и отводы; давать показания и объясняться на родном языке или языке, которым он владеет.', ARRAY['обвиняемый', 'упк', 'права', 'уголовный процесс']),

(3, 'Статья 51', 'Обязательное участие защитника', 'Участие защитника в уголовном судопроизводстве обязательно, если: обвиняемый не отказался от защитника; обвиняемый является несовершеннолетним; обвиняемый в силу физических или психических недостатков не может самостоятельно осуществлять своё право на защиту; судебное разбирательство проводится в отсутствие подсудимого.', ARRAY['защитник', 'адвокат', 'упк', 'обязательное участие']),

(3, 'Статья 91', 'Основания задержания подозреваемого', 'Орган дознания, дознаватель, следователь вправе задержать лицо по подозрению в совершении преступления, за которое может быть назначено наказание в виде лишения свободы, при наличии одного из следующих оснований: 1) когда это лицо застигнуто при совершении преступления или непосредственно после его совершения; 2) когда потерпевшие или очевидцы укажут на данное лицо как на совершившее преступление; 3) когда на этом лице или его одежде, при нём или в его жилище будут обнаружены явные следы преступления.', ARRAY['задержание', 'основания', 'упк', 'арест']),

(3, 'Статья 92', 'Порядок задержания подозреваемого', 'После доставления подозреваемого в орган дознания или к следователю в срок не более 3 часов должен быть составлен протокол задержания. В протоколе указываются дата и время составления протокола, дата, время, место, основания и мотивы задержания подозреваемого, результаты его личного обыска и другие обстоятельства его задержания. Подозреваемый должен быть допрошен не позднее 24 часов с момента его фактического задержания.', ARRAY['задержание', 'порядок', 'упк', 'протокол']),

(3, 'Статья 108', 'Заключение под стражу', 'Заключение под стражу в качестве меры пресечения применяется по судебному решению в отношении подозреваемого или обвиняемого в совершении преступлений, за которые уголовным законом предусмотрено наказание в виде лишения свободы на срок свыше трёх лет. Срок содержания под стражей при расследовании преступлений не может превышать 2 месяца.', ARRAY['заключение', 'стража', 'мера пресечения', 'арест', 'упк']),

(1, 'Статья 51', 'Право не свидетельствовать против себя', 'Никто не обязан свидетельствовать против себя самого, своего супруга и близких родственников, круг которых определяется федеральным законом. Федеральным законом могут устанавливаться иные случаи освобождения от обязанности давать свидетельские показания.', ARRAY['свидетельский иммунитет', 'конституция', 'права', 'показания']),

(1, 'Статья 48', 'Право на юридическую помощь', 'Каждому гарантируется право на получение квалифицированной юридической помощи. В случаях, предусмотренных законом, юридическая помощь оказывается бесплатно. Каждый задержанный, заключённый под стражу, обвиняемый в совершении преступления имеет право пользоваться помощью адвоката (защитника) с момента соответственно задержания, заключения под стражу или предъявления обвинения.', ARRAY['адвокат', 'юридическая помощь', 'конституция', 'задержание']),

(2, 'Статья 111', 'Умышленное причинение тяжкого вреда здоровью', 'Умышленное причинение тяжкого вреда здоровью, опасного для жизни человека, или повлёкшего за собой потерю зрения, речи, слуха либо какого-либо органа — наказывается лишением свободы на срок до восьми лет. То же деяние, совершённое в отношении двух или более лиц либо несовершеннолетнего, наказывается лишением свободы на срок до десяти лет.', ARRAY['тяжкий вред', 'здоровье', 'уголовный кодекс', 'преступление']),

(2, 'Статья 158', 'Кража', 'Кража, то есть тайное хищение чужого имущества, наказывается штрафом в размере до восьмидесяти тысяч рублей или в размере заработной платы или иного дохода осуждённого за период до шести месяцев, либо обязательными работами на срок до трёхсот шестидесяти часов, либо исправительными работами на срок до одного года, либо лишением свободы на срок до двух лет.', ARRAY['кража', 'хищение', 'уголовный кодекс', 'имущество']),

(2, 'Статья 228', 'Незаконное приобретение наркотиков', 'Незаконные приобретение, хранение, перевозка, изготовление, переработка без цели сбыта наркотических средств, психотропных веществ или их аналогов в значительном размере — наказываются штрафом в размере до сорока тысяч рублей либо лишением свободы на срок до трёх лет.', ARRAY['наркотики', 'хранение', 'уголовный кодекс', '228']),

(2, 'Статья 318', 'Применение насилия в отношении представителя власти', 'Применение насилия, не опасного для жизни или здоровья, либо угроза применения насилия в отношении представителя власти или его близких в связи с исполнением им своих должностных обязанностей — наказывается штрафом в размере до двухсот тысяч рублей либо лишением свободы на срок до пяти лет.', ARRAY['насилие', 'представитель власти', 'уголовный кодекс', 'должностное лицо']);
